ZSNAP_F01G_122.@DataWarehouse.tableFunction.script:
return select
	/*@EndUserText.label: 'G/L Account Hierarchy'*/
	MAIN."GLAccountHierarchy" as GLACCOUNTHIERARCHY,

	/*@EndUserText.label: 'Hierarchy Node'*/
	MAIN."HierarchyNode" as HIERARCHYNODE,

	/*@EndUserText.label: 'Chart of Accounts'*/
	MAIN."ChartOfAccounts" as CHARTOFACCOUNTS,

	/*@EndUserText.label: 'GL Account'*/
	MAIN."GLAccount" as GLACCOUNT,

	/*@EndUserText.label: 'Hierarchy Level'*/
	MAIN."HierarchyNodeLevel" as HIERARCHYNODELEVEL,

	/*@EndUserText.label: 'Node Length'*/
	LENGTH (MAIN."ParentNode") as NODELENGTH,

	/*@EndUserText.label: 'Node Value'*/
	MAIN."HierarchyNodeVal" as NODEVALUE,

	/*@EndUserText.label: 'Hierarchy Parent Node'*/
	MAIN."ParentNode" as PARENTNODE,

	/*@Semantics.businessDate.from: true
	@EndUserText.label: 'Validity Start Date'*/
	TO_DATE (MAIN."ValidityStartDate", 'YYYYMMDD') as VALIDITYSTARTDATE,

	/*@Semantics.businessDate.to: true
	@EndUserText.label: 'Validity End Date'*/
	TO_DATE (MAIN."ValidityEndDate", 'YYYYMMDD') as VALIDITYENDDATE
from I_GLACCOUNTHIERARCHYNODE as MAIN
where MAIN."ValidityEndDate" = '99991231'
	and (MAIN."ChartOfAccounts" = '1000' or MAIN."ChartOfAccounts" = '');

ZSNAP_F01G_FISCALQUARTER.@DataWarehouse.tableFunction.script:
return select
	/*@EndUserText.label: 'Fiscal Year Variant'*/
	MAIN."FiscalYearVariant" as FISCALYEARVARIANT,

	/*@EndUserText.label: 'Fiscal Year'*/
	MAIN."FiscalYear" as FISCALYEAR,

	/*@EndUserText.label: 'Fiscal Quarter'
	@ObjectModel.text.element: ['FiscalQuarterText']
	@AnalyticsDetails.query.display: #KEY_TEXT*/
	MAIN."FiscalQuarter" as FISCALQUARTER,

	/*@EndUserText.label: 'Fiscal Quarter'*/
	CONCAT ('Q', MAIN."FiscalQuarter") as FISCALQUARTERTEXT
from I_FISCALCALENDARDATE as MAIN
group by MAIN."FiscalYearVariant",
	MAIN."FiscalYear",
	MAIN."FiscalQuarter";

ZSNAP_F01G_FISCALYEARQUARTER.@DataWarehouse.tableFunction.script:
return select
	/*@EndUserText.label: 'Fiscal Year Variant'*/
	MAIN."FiscalYearVariant" as FISCALYEARVARIANT,

	/*@EndUserText.label: 'Fiscal Year Quarter'
	@ObjectModel.text.element: ['FiscalYearQuarterText']
	@AnalyticsDetails.query.display: #KEY_TEXT*/
	MAIN."FiscalYearQuarter" as FISCALYEARQUARTER,
	MAIN."FiscalYear" || ' ' || CONCAT ('Q', MAIN."FiscalQuarter") as FISCALYEARQUARTERTEXT
from I_FISCALCALENDARDATE as MAIN
group by MAIN."FiscalYearVariant",
	MAIN."FiscalYearQuarter",
	MAIN."FiscalYear",
	MAIN."FiscalQuarter";

