	@Semantics.text: true*/
	cast ('Intercompany' as NVARCHAR(12)) as DESCRIPTION
from I_LANGUAGE as MAIN
where MAIN."Language" = 'E'
union all select
	cast ('' as NVARCHAR(1)) as SUPPLIERISINTERCOMPANY,
	cast ('External' as NVARCHAR(12)) as DESCRIPTION
from I_LANGUAGE as MAIN
where MAIN."Language" = 'E';

ZSNAP_F01C_P_SIGNAGE.@DataWarehouse.tableFunction.script:
return select
	/*@EndUserText.label: 'Signage'
	@ObjectModel.text.element: ['Description']
	@AnalyticsDetails.query.display: #TEXT*/
	'A' as P_SIGNAGE,

	/*@EndUserText.label: 'Signage Description'
	@Semantics.text: true*/
	cast ('Payments Are Positive' as NVARCHAR(21)) as DESCRIPTION
from I_LANGUAGE as MAIN
where MAIN."Language" = 'E'
union all select
	'R' as P_SIGNAGE,
	cast ('Open AP is Positive' as NVARCHAR(21)) as DESCRIPTION
from I_LANGUAGE as MAIN
where MAIN."Language" = 'E';
